#include <stdio.h>
#include <string.h>
#define MAXLEN 105
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    char animal[MAXLEN], dog[MAXLEN], labrador[MAXLEN];
    for(int tc=0; tc<T; ++tc){
        fgets(animal, MAXLEN, stdin);
        fgets(dog, MAXLEN, stdin);
        fgets(labrador, MAXLEN, stdin);
        animal[strcspn(animal, "\n")] = 0;
        dog[strcspn(dog, "\n")] = 0;
        labrador[strcspn(labrador, "\n")] = 0;
        printf("%s makes a sound.\n", animal);
        printf("%s makes a sound.\n", dog);
        printf("%s barks.\n", dog);
        printf("%s makes a sound.\n", labrador);
        printf("%s barks.\n", labrador);
        printf("%s can swim.\n", labrador);
    }
    return 0;
}

