code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if(first==null||first.isEmpty()) return;
        int T = Integer.parseInt(first.trim());
        StringBuilder out = new StringBuilder();
        for(int tc=0; tc<T; ++tc){
            String animal = br.readLine();
            String dog = br.readLine();
            String labrador = br.readLine();
            out.append(animal).append(" makes a sound.\n");
            out.append(dog).append(" makes a sound.\n");
            out.append(dog).append(" barks.\n");
            out.append(labrador).append(" makes a sound.\n");
            out.append(labrador).append(" barks.\n");
            out.append(labrador).append(" can swim.\n");
        }
        System.out.print(out.toString());
    }
}

